{{- with .cxt}} {{/* Apply proper context from dict */}}
{{- if (and .Params.cover.image (not $.isHidden)) }}
<figure class="entry-cover">
    {{- $loading := cond $.IsSingle "eager" "lazy" }}
    {{- $addLink := (and site.Params.cover.linkFullImages $.IsSingle) }}
    {{- $prod := (hugo.IsProduction | or (eq site.Params.env "production")) }}
    {{- $alt := (.Params.cover.alt | default .Params.cover.caption | plainify) }}
    {{- $responsiveImages := (.Params.cover.responsiveImages | default site.Params.cover.responsiveImages) | default true }}

    {{- $pageBundleCover := (.Resources.ByType "image").GetMatch (printf "*%s*" (.Params.cover.image)) }}
    {{- $globalResourcesCover := (resources.ByType "image").GetMatch (printf "*%s*" (.Params.cover.image)) }}
    {{- $cover := (or $pageBundleCover $globalResourcesCover)}}
    {{- /* We are not using the .Param.cover.relative to decide the location of image */}}
    {{- /* If we have the image in pageBundle or globalResources we can process the image */}}

    {{- $sizes := (slice "360" "480" "720" "1080" "1500") }}

{{- $processableFormats := (slice "jpg" "jpeg" "png" "tif" "bmp" "gif") -}}
    {{- if hugo.IsExtended -}}
        {{- $processableFormats = $processableFormats | append "webp" -}}
    {{- end -}}

    {{- $imgdl := (.Params.cover.image) | absURL }}
    {{- if $cover -}}
        {{- $imgdl = $cover.Permalink }}
    {{- end -}}

    {{- if $addLink }}
        <a href="{{ $imgdl }}" target="_blank" rel="noopener noreferrer">
    {{- end }}

    {{- if $cover -}}
        {{/* i.e it is present in page bundle */}}
        {{- if (and (in $processableFormats $cover.MediaType.SubType) ($responsiveImages) (eq $prod true)) }}
            <img loading="{{$loading}}"
                srcset='{{- range $size := $sizes -}}

{{ $scssMain := "scss/main.scss" -}}
{{ $css := resources.Get $scssMain
      | toCSS (dict "enableSourceMap" (not hugo.IsProduction)) -}}

{{ if eq .Site.Language.LanguageDirection "rtl" -}}
  {{ $css = $css
      | postCSS (dict "use" "autoprefixer rtlcss" "noMap" true)
      | resources.Copy (replace $scssMain "." ".rtl.") -}}
{{ else if hugo.IsProduction -}}
  {{ $css = $css | postCSS -}}
{{ end -}}

{{ if hugo.IsProduction -}}
  {{ $css = $css | minify | fingerprint -}}
  <link rel="preload" href="{{ $css.RelPermalink }}" as="style" integrity="{{ $css.Data.Integrity }}" crossorigin="anonymous">
{{ end -}}

{{ with $css -}}
  <link href="{{ .RelPermalink }}" rel="stylesheet"
  {{- with .Data.Integrity }} integrity="{{ . }}" crossorigin="anonymous"{{ end -}}
  >
{{ else -}}
  {{ errorf "Resource not found or error building CSS: %s" $scssMain -}}
{{ end -}}

{{- if (ge $cover.Width $size) }}
                                {{- printf "%s %s" (($cover.Resize (printf "%sx" $size)).Permalink) (printf "%sw," $size) }}
                            {{- end }}
                        {{- end }}
                        {{- printf "%s %dw" ($cover.Permalink) ($cover.Width) }}'
                src="{{ $cover.Permalink }}"
                sizes="(min-width: 768px) 720px, 100vw"
                width="{{ $cover.Width }}" height="{{ $cover.Height }}"
                alt="{{ $alt }}">
        {{- else }}{{/* Unprocessable image or responsive images disabled */}}
            <img loading="{{ $loading }}" src="{{ $imgdl }}" alt="{{ $alt }}">
        {{- end }}
    {{- else }}
        {{- /* For absolute urls and external links, no img processing here */}}
        <img loading="{{ $loading }}" src="{{ $imgdl }}" alt="{{ $alt }}">

{{- end }}

{{- if .Params.cover.image -}}
  {{- if (ne .Params.cover.relative true) }}
    <meta property="og:image" content="{{ .Params.cover.image | absURL }}">
  {{- else}}
    <meta property="og:image" content="{{ (path.Join .RelPermalink .Params.cover.image ) | absURL }}">
  {{- end}}
{{- else }}
  {{- with partial "_funcs/get-page-images" . }}
    {{- range . | first 6 }}
      <meta property="og:image" content="{{ .Permalink }}">
    {{- end }}
  {{- end }}
{{- end }}

{{- with .Params.audio }}
  {{- range . | first 6  }}
    <meta property="og:audio" content="{{ . | absURL }}">
  {{- end }}
{{- end }}

{{- with .Params.videos }}
  {{- range . | first 6 }}
    <meta property="og:video" content="{{ . | absURL }}">

{{- $.Scratch.Set "bareul" slice -}}
        <ul>
            {{- range seq (sub $firstHeaderLevel $largest) -}}
            <ul>
                {{- $.Scratch.Add "bareul" (sub (add $largest .) 1) -}}
                {{- end -}}
                {{- range $i, $header := $headers -}}
                {{- $headerLevel := index (findRE "[1-6]" . 1) 0 -}}
                {{- $headerLevel := len (seq $headerLevel) -}}

                {{/* get id="xyz" */}}
                {{- $id := index (findRE "(id=\"(.*?)\")" $header 9) 0 }}

                {{- /* strip id="" to leave xyz, no way to get regex capturing groups in hugo */ -}}
                {{- $cleanedID := replace (replace $id "id=\"" "") "\"" "" }}
                {{- $header := replaceRE "<h[1-6].*?>((.|\n])+?)</h[1-6]>" "$1" $header -}}

{% if site.twitter.username %}
  <meta name="twitter:site" content="@{{ site.twitter.username | replace: "@", "" }}">
  <meta name="twitter:title" content="{{ page_title }}">
  <meta name="twitter:description" content="{{ seo_description }}">
  <meta name="twitter:url" content="{{ canonical_url }}">

  {% if page_large_image %}
    <meta name="twitter:card" content="summary_large_image">
    <meta name="twitter:image" content="{{ page_large_image }}">
    {% if og_image_alt %}
      <meta name="twitter:image:alt" content="{{ og_image_alt }}">
    {% endif %}
  {% else %}
    <meta name="twitter:card" content="summary">
    {% if page_teaser_image %}
      <meta name="twitter:image" content="{{ page_teaser_image }}">
      {% if og_image_alt %}
        <meta name="twitter:image:alt" content="{{ og_image_alt }}">
      {% endif %}
